26	static volatile uint32_t* const src32 =
27	    (volatile uint32_t*)(SRAM_BASE + 0x0000);
28	static volatile uint32_t* const dst32 =
29	    (volatile uint32_t*)(SRAM_BASE + 0x1000);
30	static volatile struct dma_descriptor* const desc0 =
31	    (volatile struct dma_descriptor*)(SRAM_BASE + 0x2000);
32	static volatile struct dma_descriptor* const desc1 =
