36	static volatile uint32_t* const dst32b =
37	    (volatile uint32_t*)(SRAM_BASE + 0x1100);
38	
39	int main() {
40	  uart_init();
41	
42	  // ===== Test 1: Simple mem-to-mem (64 bytes = 16 words) =====
43	  const uint32_t nwords = 16;
44	  const uint32_t nbytes = nwords * 4;
45	
46	  for (uint32_t i = 0; i < nwords; i++) src32[i] = 0xDEAD0000 + i;
47	  for (uint32_t i = 0; i < nwords; i++) dst32[i] = 0;
48	
49	  desc0->src_addr = (uint32_t)(uintptr_t)src32;
50	  desc0->dst_addr = (uint32_t)(uintptr_t)dst32;
51	  desc0->len_flags = dma_make_len_flags(nbytes, 2, 0, 0, 0);
52	  desc0->next_desc = 0;
53	  desc0->poll_addr = 0;
54	  desc0->poll_mask = 0;
55	  desc0->poll_value = 0;
56	  desc0->reserved = 0;
57	
58	  dma_start((uint32_t)(uintptr_t)desc0);
59	
60	  int rc = dma_wait_done();
61	  if (rc) {
62	    uart_puts("FAIL T1\r\n");
63	    return 1;
64	  }
65	
66	  // Verify silently — only print on mismatch
67	  for (uint32_t i = 0; i < nwords; i++) {
68	    if (dst32[i] != 0xDEAD0000 + i) {
69	      uart_puts("FAIL T1v\r\n");
70	      return 1;
71	    }
72	  }
73	
74	  // ===== Test 2: Descriptor chaining =====
75	  const uint32_t nwords2 = 8;
76	  const uint32_t nbytes2 = nwords2 * 4;
77	
78	  for (uint32_t i = 0; i < nwords2; i++) src32b[i] = 0xBEEF0000 + i;
79	  for (uint32_t i = 0; i < nwords2; i++) dst32b[i] = 0;
80	  for (uint32_t i = 0; i < nwords; i++) dst32[i] = 0;
