83	  desc0->dst_addr = (uint32_t)(uintptr_t)dst32;
84	  desc0->len_flags = dma_make_len_flags(nbytes, 2, 0, 0, 0);
85	  desc0->next_desc = (uint32_t)(uintptr_t)desc1;
86	
87	  desc1->src_addr = (uint32_t)(uintptr_t)src32b;
88	  desc1->dst_addr = (uint32_t)(uintptr_t)dst32b;
89	  desc1->len_flags = dma_make_len_flags(nbytes2, 2, 0, 0, 0);
90	  desc1->next_desc = 0;
91	  desc1->poll_addr = 0;
92	  desc1->poll_mask = 0;
93	  desc1->poll_value = 0;
94	  desc1->reserved = 0;
95	
96	  dma_start((uint32_t)(uintptr_t)desc0);
97	
98	  rc = dma_wait_done();
99	  if (rc) {
100	    uart_puts("FAIL T2\r\n");
101	    return 1;
102	  }
103	
104	  for (uint32_t i = 0; i < nwords; i++) {
105	    if (dst32[i] != 0xDEAD0000 + i) {
106	      uart_puts("FAIL T2a\r\n");
107	      return 1;
108	    }
109	  }
110	  for (uint32_t i = 0; i < nwords2; i++) {
111	    if (dst32b[i] != 0xBEEF0000 + i) {
112	      uart_puts("FAIL T2b\r\n");
113	      return 1;
114	    }
115	  }
