118	// DMA a known byte sequence to UART0 WDATA. This exercises real
119	// mem-to-periph with a fixed destination address on an actual peripheral.
120	#define UART0_BASE 0x40000000
121	#define UART0_CTRL (UART0_BASE + 0x10)
122	#define UART0_STATUS (UART0_BASE + 0x14)
123	#define UART0_WDATA (UART0_BASE + 0x1c)
124	
125	#define REG32(addr) (*(volatile uint32_t*)(addr))
126	
127	  // Enable UART0 TX (same NCO formula as uart_init)
128	  {
129	    const uint32_t main_freq_mhz = clk_get_main_freq_mhz();
130	    const uint64_t nco =
131	        ((uint64_t)115200 << 20) / ((uint64_t)main_freq_mhz * 1000000);
132	    REG32(UART0_CTRL) = (uint32_t)((nco << 16) | 3);
133	  }
134	
135	  const uint32_t t3_len = 4;  // 4 bytes
136	  volatile uint8_t* const t3_src = (volatile uint8_t*)(SRAM_BASE + 0x3000);
137	  t3_src[0] = 'D';
138	  t3_src[1] = 'M';
139	  t3_src[2] = 'A';
140	  t3_src[3] = '\n';
141	
142	  desc0->src_addr = (uint32_t)(uintptr_t)t3_src;
143	  desc0->dst_addr = UART0_WDATA;
144	  desc0->len_flags =
