161	// Read UART0 STATUS register repeatedly into a buffer using fixed source.
162	// All destination words should contain the same status value.
163	#define UART0_RDATA (UART0_BASE + 0x18)
164	  const uint32_t nwords4 = 8;
165	  const uint32_t nbytes4 = nwords4 * 4;
166	
167	  for (uint32_t i = 0; i < nwords4; i++) dst32[i] = 0;
168	
169	  // Read UART0 STATUS (a real peripheral register) repeatedly
170	  desc0->src_addr = UART0_STATUS;
171	  desc0->dst_addr = (uint32_t)(uintptr_t)dst32;
172	  desc0->len_flags = dma_make_len_flags(nbytes4, 2, 1, 0, 0);  // src_fixed=1
173	  desc0->next_desc = 0;
174	  desc0->poll_addr = 0;
175	  desc0->poll_mask = 0;
176	  desc0->poll_value = 0;
177	  desc0->reserved = 0;
178	
179	  dma_start((uint32_t)(uintptr_t)desc0);
180	
181	  rc = dma_wait_done();
182	  if (rc) {
183	    uart_puts("FAIL T4\r\n");
184	    return 1;
185	  }
186	
187	  // All reads of the same status register should return the same value.
188	  // Verify all words match the first one (we don't know the exact value,
189	  // but they should be consistent).
190	  uint32_t expected_status = dst32[0];
191	  for (uint32_t i = 1; i < nwords4; i++) {
192	    if (dst32[i] != expected_status) {
193	      uart_puts("FAIL T4v\r\n");
194	      return 1;
195	    }
196	  }
