200	  // The DMA waits until the TX FIFO has space before each byte write.
201	  const uint32_t t5_len = 8;
202	  volatile uint8_t* const t5_src = (volatile uint8_t*)(SRAM_BASE + 0x3200);
203	  t5_src[0] = 'P';
204	  t5_src[1] = 'O';
205	  t5_src[2] = 'L';
206	  t5_src[3] = 'L';
207	  t5_src[4] = '_';
208	  t5_src[5] = 'O';
209	  t5_src[6] = 'K';
210	  t5_src[7] = '\n';
211	
212	  desc0->src_addr = (uint32_t)(uintptr_t)t5_src;
213	  desc0->dst_addr = UART0_WDATA;
214	  desc0->len_flags =
215	      dma_make_len_flags(t5_len, 0, 0, 1, 1);  // 1-byte, dst_fixed, poll_en
216	  desc0->next_desc = 0;
217	  desc0->poll_addr = UART0_STATUS;
218	  desc0->poll_mask = 0x00000001;   // bit 0 = TX full
219	  desc0->poll_value = 0x00000000;  // wait until TX not full
220	  desc0->reserved = 0;
221	
222	  dma_start((uint32_t)(uintptr_t)desc0);
223	
224	  rc = dma_wait_done();
225	  if (rc) {
226	    uart_puts("FAIL T5\r\n");
227	    return 1;
228	  }
229	
230	  uart_puts("PASS\r\n");
231	  return 0;
232	}
